cd "C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad" && python << 'EOF'
import csv

# ---- ASIN monthly (lingxing) ----
rows=list(csv.DictReader(open('lingxing_snapshot/asin_monthly.csv',encoding='utf-8-sig')))
def num(x):
    try: return float(x)
    except: return 0.0
main=['B0DHPN1DMJ','B0CR1R7FKP','B0CLLT85Y6','B0DCZQX11P','B0FNCQW2K3']
feb_jun=['02','03','04','05','06']

# 5-main net & vol & sessions by year (7481 + 12137 S3)
for yr in ['2025','2026']:
    v=n=s=0
    per={}
    for r in rows:
        m=r['month']; mo=m.split('-')[1]; y=m.split('-')[0]
        if y==yr and mo in feb_jun and r['asin'] in main:
            v+=num(r['volume']); n+=num(r['net_amount']); s+=num(r['sessions_total'])
            per.setdefault(r['asin'],[0,0,0])
            per[r['asin']][0]+=num(r['volume']); per[r['asin']][1]+=num(r['net_amount']); per[r['asin']][2]+=num(r['sessions_total'])
    print(f"{yr} 5main Feb-Jun: vol={v:.0f} net=${n:,.0f} sess={s:.0f} selfCVR={v/s*100:.2f}% netASP=${n/v:.0f}")
    for a in main:
        if a in per:
            vv,nn,ss=per[a]
            print(f"   {a}: vol={vv:.0f} net=${nn:,.0f} sess={ss:.0f} CVR={ (vv/ss*100) if ss else 0:.2f}% ASP=${ (nn/vv) if vv else 0:.0f}")

# self CVR excluding S3
for yr in ['2025','2026']:
    v=s=0
    for r in rows:
        m=r['month']; mo=m.split('-')[1]; y=m.split('-')[0]
        if y==yr and mo in feb_jun and r['asin'] in main and r['asin']!='B0FNCQW2K3':
            v+=num(r['volume']); s+=num(r['sessions_total'])
    print(f"{yr} 4main(excl S3) selfCVR={v/s*100:.2f}%")

# return rates Jan vs Jun 2026, gross_margin Jan
print("\nReturn rate & GM by ASIN:")
for r in rows:
    if r['month'] in ('2026-01','2026-06') and r['sid']=='7481':
        print(f"  {r['month']} {r['model']}: return_rate={num(r['return_rate'])*100:.1f}% GM={num(r['gross_margin'])*100:.1f}% ASP=${(num(r['net_amount'])/num(r['volume'])) if num(r['volume']) else 0:.0f}")
EOF
